  /**
   * Web 端 HTML 模板生成
   */function createWebTemplate(options,theme,_state){const p=options.classPrefix;const{colors}=theme;return `
<div class="${p}-container" data-ref="container">
  <!-- Header -->
  <div class="${p}-header" data-ref="header">
    <span class="${p}-header-title" data-ref="headerTitle">呼叫中</span>
    <span class="${p}-header-device" data-ref="headerDevice"></span>
  </div>

  <!-- 主视频 -->
  <div class="${p}-main-video-wrap" data-ref="mainWrap">
    <video class="${p}-main-video" data-ref="mainVideo" autoplay playsinline muted></video>
    ${createPrivacyMaskHTML(p,"privacyLocal")}
  </div>

  <!-- 副视频 -->
  <div class="${p}-sub-video-wrap" data-ref="subWrap" style="display:none">
    <video class="${p}-sub-video" data-ref="subVideo" autoplay playsinline></video>
    ${createPrivacyMaskHTML(p,"privacyRemote")}
  </div>

  <!-- 音频 -->
  <audio class="${p}-audio" data-ref="remoteAudio" autoplay></audio>

  <!-- Footer 按钮区 -->
  <div class="${p}-footer" data-ref="footer">
    <!-- 麦克风按钮 -->
    <div class="${p}-btn" data-ref="btnMic">
      <div class="${p}-btn-icon" data-ref="btnMicIcon">${icons.micOn(colors)}</div>
      <div class="${p}-btn-text">
        <span>麦克风</span>
        ${options.showDevicePicker?`<div class="${p}-btn-arrow" data-ref="micArrow">${icons.arrowUp(colors)}</div>`:""}
        <div class="${p}-device-picker" data-ref="micPicker"></div>
      </div>
    </div>

    <!-- 挂断/取消按钮 -->
    <div class="${p}-btn" data-ref="btnHangup">
      <div class="${p}-btn-icon">${icons.hangup(colors)}</div>
      <span class="${p}-btn-label" data-ref="hangupLabel">挂断</span>
    </div>

    <!-- 接听按钮（仅 ringing 阶段显示） -->
    <div class="${p}-btn ${p}-hidden" data-ref="btnAccept">
      <div class="${p}-btn-icon">${icons.accept(colors)}</div>
      <span class="${p}-btn-label">接听</span>
    </div>

    <!-- 摄像头按钮 -->
    <div class="${p}-btn" data-ref="btnCamera">
      <div class="${p}-btn-icon" data-ref="btnCameraIcon">${icons.cameraOn(colors)}</div>
      <div class="${p}-btn-text">
        <span>摄像头</span>
        ${options.showDevicePicker?`<div class="${p}-btn-arrow" data-ref="cameraArrow">${icons.arrowUp(colors)}</div>`:""}
        <div class="${p}-device-picker" data-ref="cameraPicker"></div>
      </div>
    </div>
  </div>
</div>`.trim()}

  /**
   * Web 端 CSS 生成
   */function generateWebCSS(theme,prefix){const{colors,layout}=theme;const p=prefix;return `
.${p}-container {
  position: relative;
  width: ${layout.width}px;
  height: ${layout.height}px;
  background: ${colors.background};
  border-radius: ${layout.borderRadius}px;
  overflow: hidden;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  user-select: none;
}

.${p}-header {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 136px;
  text-align: center;
  padding-top: 32px;
  z-index: 9;
  background: linear-gradient(to bottom, rgba(0,0,0,0.65), transparent);
  transition: opacity 0.3s ease;
}

.${p}-header-title {
  height: 32px;
  font-size: 32px;
  font-weight: 500;
  color: #fff;
  display: block;
  line-height: 32px;
}

.${p}-header-device {
  height: 24px;
  font-size: 24px;
  color: #fff;
  display: block;
  margin-top: 16px;
  line-height: 24px;
}

.${p}-main-video-wrap {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  cursor: pointer;
}

.${p}-main-video {
  width: 100%;
  height: 100%;
}

.${p}-sub-video-wrap {
  position: absolute;
  right: 40px;
  top: 40px;
  width: 140px;
  height: 250px;
  border-radius: 8px;
  border: 1px solid #aaa;
  background: #000;
  z-index: 9;
  overflow: hidden;
  cursor: pointer;
}

.${p}-sub-video {
  width: calc(100% + 4px);
  height: 100%;
  margin-left: -2px;
}

.${p}-audio {
  display: none;
}

.${p}-footer {
  padding: 0 15%;
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 176px;
  padding-top: 24px;
  z-index: 9;
  background: linear-gradient(to top, rgba(0,0,0,0.6), transparent);
  transition: opacity 0.3s ease;
}

.${p}-btn {
  width: 80px;
  height: 80px;
  cursor: pointer;
  border-radius: 40px;
  text-align: center;
  position: relative;
}

.${p}-btn-icon {
  width: 80px;
  height: 80px;
  border-radius: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.${p}-btn-icon svg {
  width: 80px;
  height: 80px;
  border-radius: 40px;
}

.${p}-btn-label {
  display: block;
  margin-top: 16px;
  color: rgba(255, 255, 255, 0.9);
  font-size: 24px;
  line-height: 24px;
  user-select: none;
  white-space: nowrap;
}

.${p}-btn-text {
  display: flex;
  flex-wrap: nowrap;
  align-items: center;
  position: relative;
}

.${p}-btn-text > span {
  display: block;
  margin-top: 16px;
  color: rgba(255, 255, 255, 0.9);
  font-size: 24px;
  line-height: 24px;
  user-select: none;
  white-space: nowrap;
}

.${p}-btn-arrow {
  width: 16px;
  height: 16px;
  margin-top: 15px;
  margin-left: 2px;
  cursor: pointer;
  display: inline-flex;
  align-items: center;
}

.${p}-btn-arrow svg {
  width: 16px;
  height: 8px;
}

.${p}-device-picker {
  position: absolute;
  bottom: 100%;
  left: 50%;
  transform: translateX(-50%);
  width: 200px;
  display: none;
  padding: 16px 0;
  border-radius: 16px;
  background: rgba(44, 44, 46, 1);
  z-index: 20;
}

.${p}-device-picker.visible {
  display: flex;
  flex-direction: column;
}

.${p}-device-item {
  width: auto;
  margin: 0 8px;
  padding: 12px 16px;
  color: rgba(255, 255, 255, 0.9);
  font-size: 16px;
  line-height: 22px;
  letter-spacing: 0.19px;
  text-align: left;
  user-select: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-radius: 8px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.${p}-device-item:hover {
  background: rgb(74, 74, 78);
}

.${p}-device-item > span:first-child {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
}

.${p}-device-item .${p}-device-check {
  flex-shrink: 0;
  width: 24px;
  height: 24px;
  margin-left: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.${p}-hidden {
  display: none !important;
}

${createPrivacyMaskCSS(p,colors.overlay)}

${Toast.generateCSS(p)}
`.trim()}

